import React, { useState } from 'react';
import axios from 'axios';

function HireMeForm() {
  const [formData, setFormData] = useState({
    fullName: '', // हे रिकामे ठेवले आहे जेणेकरून बॉक्समध्ये काही दिसणार नाही
    email: '',
    serviceType: 'Web Development',
    paymentMethod: 'UPI'
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post('http://localhost:5000/api/hire', formData);
      alert("🚀 Request Sent! I will contact you soon.");
      setFormData({ fullName: '', email: '', serviceType: 'Web Development', paymentMethod: 'UPI' });
    } catch (err) {
      alert("❌ Something went wrong!");
    }
  };

  return (
    <div className="hire-container">
      <style>{`
        @import url('https://fonts.googleapis.com');
        
        .hire-container {
          display: flex;
          justify-content: center;
          align-items: center;
          min-height: 100vh;
          background: #f4f7fa;
          font-family: 'Plus Jakarta Sans', sans-serif;
          padding: 20px;
        }

        .hire-card {
          background: white;
          padding: 40px;
          border-radius: 30px; /* तुमच्या फोटोप्रमाणे जास्त राउंडेड कोपरे */
          box-shadow: 0 15px 35px rgba(0,0,0,0.05);
          width: 100%;
          max-width: 450px;
        }

        .hire-card h2 {
          font-weight: 800;
          color: #1a202c;
          text-align: center;
          font-size: 2rem;
          margin-bottom: 30px;
        }

        .form-group { margin-bottom: 25px; }

        .form-group label {
          display: block;
          font-size: 0.75rem;
          font-weight: 800;
          color: #6b7280; /* फोटोप्रमाणे ग्रे कलर */
          text-transform: uppercase;
          margin-bottom: 10px;
          letter-spacing: 0.5px;
        }

        /* इनपुट बॉक्सची स्टाइल फोटोप्रमाणे सुधारली आहे */
        .form-group input, .form-group select {
          width: 100%;
          padding: 16px 20px;
          border-radius: 18px; /* जास्त राउंडेड कोपरे */
          border: 2px solid #f3f4f6;
          background: #f9fafb;
          font-size: 1rem;
          transition: all 0.3s ease;
          outline: none;
          color: #374151;
        }

        /* क्लिक केल्यावर निळा बॉर्डर येण्यासाठी */
        .form-group input:focus {
          border-color: #3b82f6;
          background: white;
          box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.1);
        }

        .submit-btn {
          width: 100%;
          padding: 16px;
          background: #111; /* प्रोफेशनल ब्लॅक बटन */
          color: white;
          border: none;
          border-radius: 15px;
          font-weight: 700;
          font-size: 1rem;
          cursor: pointer;
          transition: 0.3s;
          margin-top: 10px;
        }

        .submit-btn:hover { background: #333; transform: translateY(-2px); }
      `}</style>

      <div className="hire-card">
        <h2>Hire Me</h2>
        <form onSubmit={handleSubmit}>
          {/* १. FULL NAME - इथे आता फक्त नाव लिहायची जागा असेल */}
          <div className="form-group">
            <label>Full Name</label>
            <input 
              type="text" 
              placeholder="Enter your name" 
              value={formData.fullName}
              onChange={(e) => setFormData({...formData, fullName: e.target.value})}
              required 
            />
          </div>

          {/* २. EMAIL ADDRESS */}
          <div className="form-group">
            <label>Email Address</label>
            <input 
              type="email" 
              placeholder="name@example.com" 
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
              required 
            />
          </div>

          <div className="form-group">
            <label>Select Service</label>
            <select 
              value={formData.serviceType}
              onChange={(e) => setFormData({...formData, serviceType: e.target.value})}
            >
              <option value="Web Development">Web Development</option>
              <option value="UI/UX Design">UI/UX Design</option>
              <option value="App Development">App Development</option>
            </select>
          </div>

          <button type="submit" className="submit-btn">
            Send Request
          </button>
        </form>
      </div>
    </div>
  );
}

export default HireMeForm;
